tests.source_program:
define i1 @cmpeq_xor_cst1_commuted(i32 %a, i32 %b) {
  %b2 = mul i32 %b, %b
  %c = xor i32 %a, 10
  %cmp = icmp eq i32 %b2, %c
  ret i1 %cmp
}

define i1 @or_disjoint_with_constants(i8 %x) {
  %or = or disjoint i8 %x, 1
  %cmp = icmp eq i8 %or, 19
  ret i1 %cmp
}
